// filterCommentsBySection returns comments for a specific section
func filterCommentsBySection(comments []CommentWithReplies, sectionID string) []CommentWithReplies {
	var result []CommentWithReplies
	for _, c := range comments {
		cSectionID := c.Comment.SectionHint.String
		if !c.Comment.SectionHint.Valid || cSectionID == "" {
			cSectionID = "document"
		}
		if cSectionID == sectionID {
			result = append(result, c)
		}
	}
	return result
}

// groupCommentsBySection groups comments by their sectionID
func groupCommentsBySection(comments []CommentWithReplies) map[string][]CommentWithReplies {
	grouped := make(map[string][]CommentWithReplies)
	for _, c := range comments {
		sectionID := c.Comment.SectionHint.String
		if !c.Comment.SectionHint.Valid || sectionID == "" {
			sectionID = "document"
		}
		grouped[sectionID] = append(grouped[sectionID], c)
	}
	return grouped
}

// getSectionIDs returns ordered list of section IDs from comments
func getSectionIDs(comments []CommentWithReplies) []string {
	seen := make(map[string]bool)
	var ids []string
	for _, c := range comments {
		sectionID := c.Comment.SectionHint.String
		if !c.Comment.SectionHint.Valid || sectionID == "" {
			sectionID = "document"
		}
		if !seen[sectionID] {
			seen[sectionID] = true
			ids = append(ids, sectionID)
		}
	}
	return ids
}

