// SectionCommentsToggleArgs contains configuration for the section comments toggle
type SectionCommentsToggleArgs struct {
	SectionID string
	Comments  []CommentWithReplies
	UserEmail string
}

// getUniqueAuthors extracts unique author emails from comments and their replies
func getUniqueAuthors(comments []CommentWithReplies) []string {
	seen := make(map[string]bool)
	var authors []string
	for _, c := range comments {
		if !seen[c.Comment.UserEmail] {
			seen[c.Comment.UserEmail] = true
			authors = append(authors, c.Comment.UserEmail)
		}
		for _, r := range c.Replies {
			if !seen[r.UserEmail] {
				seen[r.UserEmail] = true
				authors = append(authors, r.UserEmail)
			}
		}
	}
	return authors
}

// getTotalCommentCount returns total count of comments + replies
func getTotalCommentCount(comments []CommentWithReplies) int {
	count := len(comments)
	for _, c := range comments {
		count += len(c.Replies)
	}
	return count
}

// Finds the nearest heading's id in the section-heading-row, builds full URL with fragment, copies to clipboard
func copyLinkToSectionJS(menuID string) string {
	return `
		var row = el.closest('.section-heading-row');
		var heading = row ? row.querySelector('h1[id], h2[id], h3[id], h4[id], h5[id], h6[id]') : null;
		if (heading && heading.id) {
			var url = location.origin + location.pathname + '#' + heading.id;
			navigator.clipboard.writeText(url);
		}
		$` + menuID + `.open = false;
	`
}

